class AuthenticationManager(private val context: Context) {
    private val sharedPreferences = context.getSharedPreferences("Authentication", Context.MODE_PRIVATE)
    private val AUTH_TOKEN_KEY = "auth_token"
    private val USER_ID_KEY = "user_id"

    fun saveAuthData(authToken: String, userId: String) {
        sharedPreferences.edit().apply {
            putString(AUTH_TOKEN_KEY, authToken)
            putString(USER_ID_KEY, userId)
        }.apply()
    }

    fun getAuthToken(): String? {
        return sharedPreferences.getString(AUTH_TOKEN_KEY, null)
